open Util
open Printf 
open Color

let main_miva_code = 
{|
// main.miva
// Generated by Miva init
module main;
main = () => {
  println("Hello, World");
}
|}

let lib_miva_code modn = 
{|
// lib.miva
// Generated by Miva init
module |} ^ modn ^ {|;
add = (ref a: int, ref b: int): int => {
  return a + b;
}
test add_test = (): int => {
  assert!(add(1, 2) == 3);
  0;
}
export add;
|}

let init_cmd_do init_name init_type = 
  if Sys.file_exists "miva.toml" then (
    eprintf "%s\n%!" (errize "project already initialized in this directory");
    exit 1;
  ) else (
    match init_type with
    | "bin" | "lib" -> (
      write_file "miva.toml" (
        sprintf "%s%s%s%s%s%s%s%s%s"
          "[project]\n"
          "name = \"" init_name "\"\n"
          "type = \"" init_type "\"\n"
          "\n"
          "[env]\n"
          ;
      );
      Sys.mkdir "src" 0o755;
      if String.compare init_type "bin" == 0 then (
        write_file "src/main.miva" main_miva_code
      ) else (
        write_file "src/lib.miva" (lib_miva_code init_name)
      );
      eprintf "%s\n%!"
        (infoize (sprintf "initialized %s project in %s" init_type init_name))
    )
    | _ -> (
      eprintf "%s\n%!" (errize (sprintf "unknown project type %s" init_type));
      exit 1;
    )
  )